mapper.select:

	SELECT u.public_id, u.nickname
FROM room_members rm
JOIN users u ON u.user_id = rm.user_id
WHERE rm.room_id = #{roomId}
  AND rm.last_read_message_id >= #{messageId}
  AND rm.user_id != #{senderId}

SELECT m.message_id AS messageId, ( SELECT COUNT(*) FROM room_members rm WHERE rm.room_id = m.room_id AND rm.member_status = 'ACTIVE' AND rm.user_id != m.sender_id AND ( rm.last_read_message_id IS NULL OR rm.last_read_message_id < m.message_id ) ) AS unreadCount FROM chat_messages m WHERE m.room_id = #{roomId}
AND m.message_id > #{oldLastReadMsgId}
AND m.message_id <= #{newLastReadMessageId}
ORDER BY m.message_id ASC
